INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '86e24eb0-c11a-471a-9fad-d7362aa5c8a8',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorFlow Training Loop — GradientTape, Loss, and Optimizer in One Pass$escape$,
  $escape$TensorFlow's training loop is explicit by design. Inside a `tf.GradientTape` context, every operation on watched variables is recorded to the computation graph. The forward pass runs your model, producing logits. Loss is computed immediately after — `tf.keras.losses.SparseCategoricalCrossentropy(from_logits=True)` is the idiomatic choice for classification. Calling `tape.gradient(loss, model.trainable_variables)` then differentiates the loss with respect to each variable, traversing the recorded graph in reverse. The resulting gradient list is passed to `optimizer.apply_gradients(zip(grads, model.trainable_variables))` — this is your weight update step. Critically, `tape` is consumed after one `gradient()` call; set `persistent=True` only if you need multiple gradient computations from the same forward pass. Wrapping the entire loop body in `@tf.function` compiles it to a static graph via XLA, often delivering 2–4× throughput gains over eager mode. Always benchmark with and without `@tf.function` — shape dynamism can inhibit tracing.$escape$,
  $escape$import tensorflow as tf

model = tf.keras.Sequential([tf.keras.layers.Dense(10)])
optimizer = tf.keras.optimizers.Adam(learning_rate=1e-3)
loss_fn = tf.keras.losses.SparseCategoricalCrossentropy(from_logits=True)

@tf.function
def train_step(x, y):
    with tf.GradientTape() as tape:
        logits = model(x, training=True)
        loss = loss_fn(y, logits)
    grads = tape.gradient(loss, model.trainable_variables)
    optimizer.apply_gradients(zip(grads, model.trainable_variables))
    return loss$escape$,
  $escape$python$escape$,
