INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1217665d-bb56-4a9f-8bab-c5a78facfd03',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorFlow Optimizers — SGD, Adam, AdamW, and Learning Rate Schedulers$escape$,
  $escape$TensorFlow's `tf.keras.optimizers` gives you fine-grained control over training dynamics. SGD with momentum (`tf.keras.optimizers.SGD(lr=0.01, momentum=0.9, nesterov=True)`) is still the gold standard for CNNs on well-tuned pipelines. Adam (`tf.keras.optimizers.Adam(learning_rate=1e-3)`) adapts per-parameter learning rates using first and second moment estimates — fast convergence, but can generalize worse than SGD. AdamW (`tf.keras.optimizers.AdamW(weight_decay=1e-2)`) decouples weight decay from the gradient update, fixing Adam's L2 regularization conflation — use it for transformers and modern architectures. Pair any optimizer with a `tf.keras.optimizers.schedules` policy: `CosineDecay` for smooth annealing, `ExponentialDecay` for aggressive step-downs, or `ReduceLROnPlateau` via the callback equivalent. Wrap your schedule into the optimizer directly via the `learning_rate` argument — TensorFlow will call `schedule(step)` automatically during `optimizer.apply_gradients()`. For mixed-precision training, wrap with `tf.keras.mixed_precision.LossScaleOptimizer` to prevent underflow.$escape$,
  $escape$import tensorflow as tf

# Cosine decay schedule
schedule = tf.keras.optimizers.schedules.CosineDecay(
    initial_learning_rate=1e-3,
    decay_steps=10000,
    alpha=1e-5  # minimum lr floor
)

# AdamW with decoupled weight decay + schedule
optimizer = tf.keras.optimizers.AdamW(
    learning_rate=schedule,
    weight_decay=1e-2
)

# Mixed precision wrapper for GPU/TPU
optimizer = tf.keras.mixed_precision.LossScaleOptimizer(optimizer)$escape$,
  $escape$python$escape$,
