INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '586c2d82-f8a8-4e66-852e-608844022830',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorFlow Regularization — Dropout, Weight Decay, BatchNorm, and Early Stopping$escape$,
  $escape$TensorFlow offers four primary regularization mechanisms, each targeting a different failure mode. `tf.keras.layers.Dropout(rate)` randomly zeros activations during training — wrap it after dense or conv layers, never during inference (Keras handles this via the `training` flag automatically). Weight decay is applied per-layer via `kernel_regularizer=tf.keras.regularizers.L2(1e-4)` — this adds a penalty term directly to the loss, so you'll see it reflected in `model.losses`. `tf.keras.layers.BatchNormalization()` normalizes activations per mini-batch and learns scale/shift parameters (`gamma`, `beta`); place it before the activation, not after. Critically, BatchNorm has separate train/inference behavior — always pass `training=True` explicitly in custom training loops, or it defaults to inference mode and your model won't learn. For early stopping, `tf.keras.callbacks.EarlyStopping(monitor='val_loss', patience=5, restore_best_weights=True)` halts training when validation loss stalls and resets weights to the best checkpoint. Combine all four: BatchNorm reduces need for aggressive dropout; L2 and dropout together can over-regularize — tune one at a time.$escape$,
  $escape$import tensorflow as tf

model = tf.keras.Sequential([
    tf.keras.layers.Dense(256, kernel_regularizer=tf.keras.regularizers.L2(1e-4)),
    tf.keras.layers.BatchNormalization(),
    tf.keras.layers.Activation('relu'),
    tf.keras.layers.Dropout(0.3),
    tf.keras.layers.Dense(10, activation='softmax')
])

early_stop = tf.keras.callbacks.EarlyStopping(
    monitor='val_loss', patience=5, restore_best_weights=True
)

model.compile(optimizer='adam', loss='sparse_categorical_crossentropy', metrics=['accuracy'])
model.fit(X_train, y_train, validation_split=0.2, epochs=100, callbacks=[early_stop])$escape$,
  $escape$python$escape$,
