INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ed534f6c-f581-4254-baa5-db80ad815bcb',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorFlow's JAX-Style Stack: tf.function + XLA, GradientTape, and vectorized_map$escape$,
  $escape$TensorFlow's answer to JAX's functional trio lives in `tf.function(jit_compile=True)` for XLA-fused kernel compilation, `tf.GradientTape` for explicit gradient control, and `tf.vectorized_map` for vmap-style batched parallelism — all composable within eager mode ergonomics.

Decorating a function with `@tf.function(jit_compile=True)` traces it to HLO IR and hands it to XLA, which fuses ops, eliminates temporary buffers, and typically yields 2–5× throughput gains on TPUs and modern GPUs. Unlike JAX's `jit`, TF's version handles stateful `tf.Variable` updates, but will retrace on input shape changes unless `input_signature` is explicitly set — an expensive footgun in production pipelines.

`tf.GradientTape` gives you imperative, explicit gradient computation. Nest tapes for higher-order derivatives, or call `tape.jacobian()` for per-sample Jacobians without a Python loop. For batched gradient computation, `tf.vectorized_map` maps a single-example function across the batch axis — TF's functional `vmap` equivalent — emitting one fused vectorized kernel instead of N sequential calls. Compose all three for efficient, TPU-ready training loops.$escape$,
  $escape$import tensorflow as tf

@tf.function(jit_compile=True)  # XLA: fuses ops, eliminates temp buffers
def forward(x, w):
    return tf.nn.relu(x @ w)

x = tf.random.normal([256, 64])
w = tf.Variable(tf.random.normal([64, 128]))

# Explicit gradient control via GradientTape
with tf.GradientTape() as tape:
    out = forward(x, w)
    loss = tf.reduce_mean(out ** 2)

grad = tape.gradient(loss, w)  # dL/dw

# vmap-style batching: single-example fn vectorized over batch axis
per_sample_out = tf.vectorized_map(lambda xi: forward(xi[None], w), x)
# shape: [256, 1, 128] — one fused kernel, no Python loop$escape$,
  $escape$python$escape$,
