INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e24ec658-2ca2-4c0a-9614-8fe54210223e',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorFlow Production Readiness — SavedModel, ONNX Export, and TF Serving$escape$,
  $escape$When shipping a TensorFlow model to production, the export format is your first decision. `tf.saved_model.save()` produces a SavedModel directory — the canonical format for TF Serving and TFLite. Always trace your model with concrete input signatures via `@tf.function(input_signature=[...])` before export; without it, TF Serving can't infer the serving signature and defaults to dynamic dispatch, which breaks strict type validation.

For cross-framework serving (e.g., deploying to an ONNX Runtime backend), use `tf2onnx`: `python -m tf2onnx.convert --saved-model ./model --output model.onnx --opset 17`. Opset 17 covers most TF ops, but custom `tf.keras` layers with Python-side logic (like dynamic masking) won't trace cleanly — rewrite them as pure TF ops first.

For TF Serving specifically, version your exports under a numeric subdirectory (`1/`, `2/`) — the server hot-reloads the highest integer. Warm up your model with `WarmupRequests` in `assets.extra/` to avoid cold-start latency spikes on the first batch.$escape$,
  $escape$import tensorflow as tf
import tf2onnx

class MyModel(tf.keras.Model):
    @tf.function(input_signature=[tf.TensorSpec([None, 128], tf.float32, name='input')])
    def serve(self, x):
        return {'output': self(x, training=False)}

model = MyModel()
# Attach serving signature before export
model.serve = model.serve
tf.saved_model.save(model, './export/1', signatures={'serving_default': model.serve})

# Convert to ONNX (opset 17)
onnx_model, _ = tf2onnx.convert.from_saved_model('./export/1', opset=17, output_path='model.onnx')$escape$,
  $escape$python$escape$,
